116	            </button>
117	            <button
118	              aria-label="Cancel"
119	              disabled={isSaving}
120	              onClick={() => { setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null) }}
121	            >
122	              Cancel
123	            </button>
124	          </div>
125	        ) : (
126	          <div className="modal-field-view">
127	            <h2 className="modal-title">{card.title}</h2>
