9	const __dirname = dirname(fileURLToPath(import.meta.url));
10	
11	function createApp() {
12	  const app = express();
13	  const isProduction = process.env.NODE_ENV === 'production';
14	
15	  // ── Middleware ────────────────────────────────────────────────────────────
16	  // NOTE: origin:'*' + credentials:true is invalid per CORS spec (browsers reject it).
17	  // Use origin:true (reflect request Origin) in dev so credentials can coexist if needed.
18	  app.use(cors({
19	    origin: isProduction ? false : true, // 'true' reflects the request's Origin header
20	    credentials: true,
21	  }));
22	  app.use(express.json());
23	
24	  // ── API Routes ────────────────────────────────────────────────────────────
25	  app.use('/api', commentsRouter);
26	  app.use('/api', cardsRouter);
27	
28	  // ── Routes ────────────────────────────────────────────────────────────────
29	  app.get('/health', (_req, res) => res.json({ ok: true }));
30	
31	  // Dev/test-only routes (not in production)
32	  if (!isProduction) {
33	    app.post('/dev/echo', (req, res) => res.json(req.body));
34	    app.get('/dev/error', (req, res, next) => {
35	      const err = new Error('Test error');
36	      err.status = req.query.status ? parseInt(req.query.status, 10) : 500;
37	      next(err);
38	    });
39	  }
40	
41	  // ── Static files (production) ─────────────────────────────────────────────
42	  if (isProduction) {
43	    const distPath = join(__dirname, '..', 'client', 'dist');
44	    app.use(express.static(distPath));
45	    app.get('*', (_req, res) =>
46	      res.sendFile(join(distPath, 'index.html'))
47	    );
48	  }
49	
50	  // ── 404 handler ───────────────────────────────────────────────────────────
51	  app.use((_req, res) => res.status(404).json({ error: 'Not Found' }));
52	
53	  // ── Error handler ─────────────────────────────────────────────────────────
54	  // eslint-disable-next-line no-unused-vars
55	  app.use((err, _req, res, _next) => {
56	    const status = err.status || err.statusCode || 500;
57	    res.status(status).json({ error: err.message || 'Internal Server Error' });
58	  });
59	
60	  return app;
61	}
62	
63	// Start when run as the entry point
64	// resolve() normalises relative paths before comparing
65	if (resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
66	  const app = createApp();
67	  const PORT = process.env.PORT || 3001;
68	  const server = app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
69	  initWs(server);
70	}
71	
72	export { createApp };
