            setIsEditingAssignee(false)
            setEditAssignee(card.assignee ?? '')
            setSaveError(null)
          }}
        >
          {card.title}
        </h3>
      )}

      {/* Assignee */}
      {isEditingAssignee ? (
        <div className="card-tile-field-edit">
          <input
            aria-label="Edit assignee"
            value={editAssignee}
            onChange={e => setEditAssignee(e.target.value)}
            onKeyDown={e => {
