              onChange={e => setEditAssignee(e.target.value)}
              onKeyDown={e => { if (e.key === 'Enter') { skipBlurRef.current = true; handleSaveAssignee() } }}
              onBlur={() => {
                if (skipBlurRef.current) { skipBlurRef.current = false; return }
                handleSaveAssignee()
              }}
            />
            <button aria-label="Save" onMouseDown={() => { skipBlurRef.current = true }} onClick={handleSaveAssignee} disabled={isSaving}>
              {isSaving ? 'Saving…' : 'Save'}
