import { useState, useRef, useEffect } from 'react'
import './CardTile.css'

export default function CardTile({ card, onCardClick, onUpdate }) {
  const [isEditingTitle, setIsEditingTitle]       = useState(false)
  const [editTitle, setEditTitle]                 = useState(card.title)
  const [isEditingAssignee, setIsEditingAssignee] = useState(false)
  const [editAssignee, setEditAssignee]           = useState(card.assignee ?? '')
  const [isSaving, setIsSaving]                   = useState(false)
  const [saveError, setSaveError]                 = useState(null)
  const skipBlurRef                               = useRef(false)
  const titleInputRef                             = useRef(null)
  const assigneeInputRef                          = useRef(null)

  // Auto-focus input when entering edit mode (mirrors CardModal pattern)
  useEffect(() => {
    if (isEditingTitle && titleInputRef.current) titleInputRef.current.focus()
  }, [isEditingTitle])

  useEffect(() => {
    if (isEditingAssignee && assigneeInputRef.current) assigneeInputRef.current.focus()
  }, [isEditingAssignee])

  async function handleSaveTitle() {
    if (editTitle.trim() === '') { setSaveError('Title is required'); return }
    setIsSaving(true); setSaveError(null)
    try {
      await onUpdate(card.id, { title: editTitle })
      setIsEditingTitle(false)
    } catch (err) {
      setEditTitle(card.title)        // local rollback
      setIsEditingTitle(false)        // exit edit mode on failure
      setSaveError(err.message)
    } finally { setIsSaving(false) }
  }

  async function handleSaveAssignee() {
    setIsSaving(true); setSaveError(null)
    try {
      await onUpdate(card.id, { assignee: editAssignee === '' ? null : editAssignee })
      setIsEditingAssignee(false)
    } catch (err) {
      setEditAssignee(card.assignee ?? '')  // local rollback
      setIsEditingAssignee(false)
      setSaveError(err.message)
    } finally { setIsSaving(false) }
  }

  const isEditing = isEditingTitle || isEditingAssignee

  return (
    <div
      className={`card-tile${isEditing ? ' card-tile-editing' : ''}`}
      role="button"
      tabIndex={0}
      onClick={() => !isEditing && onCardClick(card)}
      onKeyDown={e => {
        if (isEditing) return
        if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); onCardClick(card) }
      }}
      aria-label={card.title}
    >
      {/* Title */}
      {isEditingTitle ? (
        <div className="card-tile-field-edit">
          <input
            ref={titleInputRef}
            aria-label="Edit title"
            value={editTitle}
            onChange={e => setEditTitle(e.target.value)}
            onKeyDown={e => {
              if (e.key === 'Enter')  { skipBlurRef.current = true; handleSaveTitle() }
              if (e.key === 'Escape') { skipBlurRef.current = true; setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null) }
            }}
            onBlur={() => {
              if (skipBlurRef.current) { skipBlurRef.current = false; return }
              handleSaveTitle()
            }}
          />
          {isSaving && <span aria-label="Saving">Saving…</span>}
        </div>
      ) : (
        <h3
          className="card-tile-title"
          onClick={e => {
            e.stopPropagation()
            setEditTitle(card.title)
            setIsEditingTitle(true)
            // Mutual exclusivity: close assignee edit if open
            setIsEditingAssignee(false)
            setEditAssignee(card.assignee ?? '')
            setSaveError(null)
          }}
        >
          {card.title}
        </h3>
      )}

      {/* Assignee */}
      {isEditingAssignee ? (
        <div className="card-tile-field-edit">
          <input
            ref={assigneeInputRef}
            aria-label="Edit assignee"
            value={editAssignee}
            onChange={e => setEditAssignee(e.target.value)}
            onKeyDown={e => {
              if (e.key === 'Enter')  { skipBlurRef.current = true; handleSaveAssignee() }
              if (e.key === 'Escape') { skipBlurRef.current = true; setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null) }
            }}
            onBlur={() => {
              if (skipBlurRef.current) { skipBlurRef.current = false; return }
              handleSaveAssignee()
            }}
          />
          {isSaving && <span aria-label="Saving">Saving…</span>}
        </div>
      ) : (
        <p
          className="card-tile-assignee"
          onClick={e => {
            e.stopPropagation()
            setEditAssignee(card.assignee ?? '')
            setIsEditingAssignee(true)
            // Mutual exclusivity: close title edit if open
            setIsEditingTitle(false)
            setEditTitle(card.title)
            setSaveError(null)
          }}
        >
          {card.assignee ?? 'Unassigned'}
        </p>
      )}

      {card.description && <p className="card-tile-description">{card.description}</p>}
      {saveError && <p role="alert" className="card-tile-error">{saveError}</p>}
    </div>
  )
}

  // Validation
  it('empty title shows validation error and does not call onUpdate', () => {
    const onUpdate = vi.fn()
    render(<CardTile card={card} onCardClick={vi.fn()} onUpdate={onUpdate} />)
    fireEvent.click(screen.getByRole('heading', { name: 'Fix bug' }))
    fireEvent.change(screen.getByRole('textbox', { name: 'Edit title' }), { target: { value: '' } })
    fireEvent.keyDown(screen.getByRole('textbox', { name: 'Edit title' }), { key: 'Enter' })
    expect(screen.getByRole('alert')).toHaveTextContent('Title is required')
    expect(onUpdate).not.toHaveBeenCalled()
  })

  it('whitespace-only title shows validation error and does not call onUpdate', () => {
    const onUpdate = vi.fn()
    render(<CardTile card={card} onCardClick={vi.fn()} onUpdate={onUpdate} />)
    fireEvent.click(screen.getByRole('heading', { name: 'Fix bug' }))
    fireEvent.change(screen.getByRole('textbox', { name: 'Edit title' }), { target: { value: '   ' } })
    fireEvent.keyDown(screen.getByRole('textbox', { name: 'Edit title' }), { key: 'Enter' })
    expect(screen.getByRole('alert')).toHaveTextContent('Title is required')
    expect(onUpdate).not.toHaveBeenCalled()
  })

  // Error handling and rollback
  it('onUpdate failure on title save exits edit mode and restores original title', async () => {
    const onUpdate = vi.fn().mockRejectedValue(new Error('Server error'))
    render(<CardTile card={card} onCardClick={vi.fn()} onUpdate={onUpdate} />)
    fireEvent.click(screen.getByRole('heading', { name: 'Fix bug' }))
    fireEvent.change(screen.getByRole('textbox', { name: 'Edit title' }), { target: { value: 'New title' } })
    fireEvent.keyDown(screen.getByRole('textbox', { name: 'Edit title' }), { key: 'Enter' })
    await waitFor(() => expect(screen.queryByRole('textbox', { name: 'Edit title' })).not.toBeInTheDocument())
    expect(screen.getByRole('heading', { name: 'Fix bug' })).toBeInTheDocument()
  })

  it('onUpdate failure on title save shows an error alert', async () => {
    const onUpdate = vi.fn().mockRejectedValue(new Error('Server error'))
    render(<CardTile card={card} onCardClick={vi.fn()} onUpdate={onUpdate} />)
    fireEvent.click(screen.getByRole('heading', { name: 'Fix bug' }))
    fireEvent.keyDown(screen.getByRole('textbox', { name: 'Edit title' }), { key: 'Enter' })
    await waitFor(() => expect(screen.getByRole('alert')).toHaveTextContent('Server error'))
  })

  it('onUpdate failure on assignee save exits edit mode and shows an error alert', async () => {
    const onUpdate = vi.fn().mockRejectedValue(new Error('Assignee error'))
    render(<CardTile card={card} onCardClick={vi.fn()} onUpdate={onUpdate} />)
    fireEvent.click(screen.getByText('Alice'))
    fireEvent.keyDown(screen.getByRole('textbox', { name: 'Edit assignee' }), { key: 'Enter' })
    await waitFor(() => expect(screen.getByRole('alert')).toHaveTextContent('Assignee error'))
    expect(screen.queryByRole('textbox', { name: 'Edit assignee' })).not.toBeInTheDocument()
  })

  // Visual feedback
  it('title edit mode applies card-tile-editing class to the tile', () => {
    render(<CardTile card={card} onCardClick={vi.fn()} onUpdate={vi.fn()} />)
    fireEvent.click(screen.getByRole('heading', { name: 'Fix bug' }))
    expect(screen.getByRole('button', { name: 'Fix bug' })).toHaveClass('card-tile-editing')
  })

  it('assignee edit mode applies card-tile-editing class to the tile', () => {
    render(<CardTile card={card} onCardClick={vi.fn()} onUpdate={vi.fn()} />)
    fireEvent.click(screen.getByText('Alice'))
    expect(screen.getByRole('button', { name: 'Fix bug' })).toHaveClass('card-tile-editing')
  })

  it('shows saving indicator while save is in-flight', async () => {
    const onUpdate = vi.fn().mockReturnValue(new Promise(() => {}))
    render(<CardTile card={card} onCardClick={vi.fn()} onUpdate={onUpdate} />)
    fireEvent.click(screen.getByRole('heading', { name: 'Fix bug' }))
    fireEvent.keyDown(screen.getByRole('textbox', { name: 'Edit title' }), { key: 'Enter' })
    await waitFor(() => expect(screen.getByLabelText('Saving')).toBeInTheDocument())
  })
})

