              aria-label="Cancel"
              disabled={isSaving}
              onMouseDown={() => { skipBlurRef.current = true }}
              onClick={() => { setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null) }}
            >
              Cancel
            </button>
          </div>
        ) : (
